// ConnectionScreen.jsx — Step 1: DB connection input

import { useState } from "react";
import { connectDatabase } from "../api";

const EXAMPLES = [
  { label: "Supabase", value: "postgresql://postgres:password@db.xxx.supabase.co:5432/postgres" },
  { label: "PostgreSQL", value: "postgresql://user:password@localhost:5432/mydb" },
  { label: "MySQL", value: "mysql+pymysql://user:password@localhost:3306/mydb" },
  { label: "SQLite", value: "sqlite:///path/to/file.db" },
];

export default function ConnectionScreen({ onConnected }) {
  const [connStr, setConnStr] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleConnect = async () => {
    if (!connStr.trim()) return;
    setLoading(true);
    setError("");
    try {
      const data = await connectDatabase(connStr.trim());
      onConnected(data);
    } catch (e) {
      setError(e.response?.data?.detail || "Connection failed. Check your connection string.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.screen}>
      {/* Background grid */}
      <div style={styles.grid} />

      <div style={styles.card} className="fade-up">
        {/* Logo */}
        <div style={styles.logoRow}>
          <div style={styles.logoIcon}>
            <svg width="28" height="28" viewBox="0 0 28 28" fill="none">
              <circle cx="14" cy="14" r="13" stroke="#4f8ef7" strokeWidth="1.5"/>
              <path d="M8 18 L12 10 L16 15 L20 8" stroke="#4f8ef7" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
              <circle cx="20" cy="8" r="2" fill="#7c5cfc"/>
            </svg>
          </div>
          <div>
            <h1 style={styles.logo}>Talking BI</h1>
            <p style={styles.tagline}>AI-Powered Business Intelligence</p>
          </div>
        </div>

        <div style={styles.divider} />

        <h2 style={styles.heading}>Connect your database</h2>
        <p style={styles.sub}>Paste your connection string below to get started</p>

        {/* Input */}
        <div style={styles.inputWrap}>
          <div style={styles.inputIcon}>
            <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
              <rect x="1" y="3" width="14" height="10" rx="2" stroke="#4a5270" strokeWidth="1.5"/>
              <path d="M5 7h6M5 9.5h4" stroke="#4a5270" strokeWidth="1.5" strokeLinecap="round"/>
            </svg>
          </div>
          <input
            style={styles.input}
            placeholder="postgresql://user:password@host:5432/dbname"
            value={connStr}
            onChange={(e) => setConnStr(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && handleConnect()}
            spellCheck={false}
          />
        </div>

        {/* Examples */}
        <div style={styles.exampleRow}>
          <span style={styles.exampleLabel}>Quick fill:</span>
          {EXAMPLES.map((ex) => (
            <button
              key={ex.label}
              style={styles.exampleBtn}
              onClick={() => setConnStr(ex.value)}
            >
              {ex.label}
            </button>
          ))}
        </div>

        {/* Error */}
        {error && (
          <div style={styles.error}>
            <span>⚠️</span> {error}
          </div>
        )}

        {/* Connect button */}
        <button
          style={{ ...styles.btn, ...(loading ? styles.btnDisabled : {}) }}
          onClick={handleConnect}
          disabled={loading}
        >
          {loading ? (
            <span style={styles.spinner} />
          ) : (
            <svg width="18" height="18" viewBox="0 0 18 18" fill="none">
              <path d="M3 9h12M9 3l6 6-6 6" stroke="#fff" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
          )}
          {loading ? "Connecting..." : "Connect Database"}
        </button>

        {/* Footer hint */}
        <p style={styles.hint}>
          🔒 Your connection string is only used locally and never stored.
        </p>
      </div>
    </div>
  );
}

const styles = {
  screen: {
    minHeight: "100vh",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    padding: "24px",
    position: "relative",
    overflow: "hidden",
  },
  grid: {
    position: "fixed",
    inset: 0,
    backgroundImage: `linear-gradient(rgba(79,142,247,0.04) 1px, transparent 1px),
                      linear-gradient(90deg, rgba(79,142,247,0.04) 1px, transparent 1px)`,
    backgroundSize: "48px 48px",
    pointerEvents: "none",
  },
  card: {
    background: "rgba(15,17,23,0.95)",
    border: "1px solid var(--border)",
    borderRadius: "var(--radius-lg)",
    padding: "48px",
    width: "100%",
    maxWidth: "560px",
    backdropFilter: "blur(20px)",
    boxShadow: "0 0 0 1px rgba(79,142,247,0.1), 0 32px 64px rgba(0,0,0,0.6)",
    position: "relative",
  },
  logoRow: {
    display: "flex",
    alignItems: "center",
    gap: "14px",
    marginBottom: "32px",
  },
  logoIcon: {
    width: "52px",
    height: "52px",
    background: "rgba(79,142,247,0.1)",
    border: "1px solid rgba(79,142,247,0.2)",
    borderRadius: "14px",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
  },
  logo: {
    fontSize: "26px",
    fontWeight: 800,
    color: "#fff",
    letterSpacing: "-0.5px",
  },
  tagline: {
    fontSize: "12px",
    color: "var(--text2)",
    letterSpacing: "0.05em",
    textTransform: "uppercase",
  },
  divider: {
    height: "1px",
    background: "var(--border)",
    marginBottom: "32px",
  },
  heading: {
    fontSize: "22px",
    fontWeight: 700,
    color: "#fff",
    marginBottom: "8px",
  },
  sub: {
    fontSize: "14px",
    color: "var(--text2)",
    marginBottom: "24px",
  },
  inputWrap: {
    position: "relative",
    marginBottom: "12px",
  },
  inputIcon: {
    position: "absolute",
    left: "14px",
    top: "50%",
    transform: "translateY(-50%)",
    pointerEvents: "none",
  },
  input: {
    width: "100%",
    padding: "14px 14px 14px 42px",
    background: "var(--bg3)",
    border: "1px solid var(--border2)",
    borderRadius: "var(--radius)",
    color: "var(--text)",
    fontSize: "13px",
    fontFamily: "'DM Mono', 'Fira Code', monospace",
    outline: "none",
    transition: "border-color 0.2s",
  },
  exampleRow: {
    display: "flex",
    alignItems: "center",
    gap: "8px",
    flexWrap: "wrap",
    marginBottom: "20px",
  },
  exampleLabel: {
    fontSize: "12px",
    color: "var(--text3)",
  },
  exampleBtn: {
    padding: "4px 10px",
    background: "var(--bg3)",
    border: "1px solid var(--border2)",
    borderRadius: "6px",
    color: "var(--text2)",
    fontSize: "12px",
    cursor: "pointer",
    transition: "all 0.15s",
  },
  error: {
    display: "flex",
    alignItems: "center",
    gap: "8px",
    padding: "12px 16px",
    background: "rgba(247,89,89,0.1)",
    border: "1px solid rgba(247,89,89,0.3)",
    borderRadius: "var(--radius)",
    color: "#f79999",
    fontSize: "13px",
    marginBottom: "16px",
  },
  btn: {
    width: "100%",
    padding: "15px",
    background: "linear-gradient(135deg, var(--accent), var(--accent2))",
    border: "none",
    borderRadius: "var(--radius)",
    color: "#fff",
    fontSize: "15px",
    fontWeight: 600,
    fontFamily: "'Syne', sans-serif",
    cursor: "pointer",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    gap: "10px",
    transition: "opacity 0.2s, transform 0.2s",
    marginBottom: "20px",
  },
  btnDisabled: {
    opacity: 0.6,
    cursor: "not-allowed",
  },
  spinner: {
    width: "18px",
    height: "18px",
    border: "2px solid rgba(255,255,255,0.3)",
    borderTopColor: "#fff",
    borderRadius: "50%",
    animation: "spin 0.7s linear infinite",
    display: "inline-block",
  },
  hint: {
    textAlign: "center",
    fontSize: "12px",
    color: "var(--text3)",
  },
};
